import json
with open('baseline-packages.json') as f: base = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    result = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                pkgs[pkg['id']] = pkg['resolvedVersion']
        result[pname] = pkgs
    return result

bp = get_pkgs(base)
ap = get_pkgs(after)

changes = []
unchanged = []
for proj in sorted(set(list(bp.keys()) + list(ap.keys()))):
    for pkg in sorted(set(list(bp.get(proj,{}).keys()) + list(ap.get(proj,{}).keys()))):
        bv = bp.get(proj,{}).get(pkg, 'N/A')
        av = ap.get(proj,{}).get(pkg, 'N/A')
        if bv != av:
            changes.append((proj, pkg, bv, av))
        else:
            unchanged.append((proj, pkg, bv))

print('=== CHANGES ===')
if changes:
    for c in changes: print(f'  {c[0]}: {c[1]} {c[2]} -> {c[3]}')
else:
    print('  None')
print()
print(f'=== UNCHANGED: {len(unchanged)} package-project pairs ===')
"

